FROM eb_admin a
LEFT JOIN eb_admin_info i ON i.id = a.id
WHERE a.deleted_at IS NULL
AND EXISTS (SELECT 1 FROM eb_frame_assist fa0 WHERE fa0.user_id = a.id AND fa0.entid = #{q.entid} AND fa0.deleted_at IS NULL)

	AND i.type IN
	#{t}


	AND i.type = #{q.singleType}


	AND i.work_time >= #{q.timeStart}


	AND i.work_time <= CONCAT(#{q.timeEnd}, ' 23:59:59')


	AND i.quit_time >= #{q.timeStart}


	AND i.quit_time <= CONCAT(#{q.timeEnd}, ' 23:59:59')


	AND i.education = #{q.education}


	AND i.sex = #{q.sex}


	AND i.is_part = #{q.isPart}


	AND a.status = #{q.status}


	AND (a.name LIKE CONCAT('%', #{q.search}, '%') OR a.phone LIKE CONCAT('%', #{q.search}, '%'))


	AND a.id IN (SELECT fa1.user_id FROM eb_frame_assist fa1 WHERE fa1.frame_id = #{q.frameId} AND fa1.entid = #{q.entid} AND fa1.deleted_at IS NULL)

FROM eb_admin a
INNER JOIN eb_admin_info i ON i.id = a.id
INNER JOIN eb_frame_assist fa ON fa.user_id = a.id
	AND fa.entid = #{p.entid}
	AND fa.deleted_at IS NULL
WHERE a.deleted_at IS NULL

	AND i.type IN
	#{t}


	AND (a.name LIKE CONCAT('%', #{p.name}, '%') OR a.phone LIKE CONCAT('%', #{p.name}, '%'))


	AND a.job = #{p.jobId}


	AND (


			fa.frame_id IN
			#{fid}
			OR fa.frame_id = #{p.frameId}


			fa.frame_id = #{p.frameId}


	)




			AND a.id IN
			#{aid}


			AND 1 = 0
